import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPMessage;

@WebService
public class OrderProcessingService {

    @WebMethod
    public String processOrder(SOAPMessage message) throws SOAPException {
        String responseMessage;
        double totalPrice = 0.0;

        // Parse the SOAP message to extract order details
        String itemDetails = message.getSOAPBody().getTextContent();
        String[] items = itemDetails.split(";");

        for (String item : items) {
            String[] details = item.split(",");
            String itemName = details[0];
            double itemPrice = Double.parseDouble(details[1]);
            int quantity = Integer.parseInt(details[2]);
            totalPrice += itemPrice * quantity;
        }

        // Process the order (e.g., save to database, etc.)
        // For simplicity, we will just create a response message
        responseMessage = "Order processed successfully. Total Price: $" + totalPrice;

        return responseMessage;
    }
}